import * as React from "react";
import { SelectedFeature, LayerMetadata, FeatureProperty } from "../api/contracts/query";
import { Toolbar, type IItem, DEFAULT_TOOLBAR_SIZE, TOOLBAR_BACKGROUND_COLOR } from "./toolbar";
import { tr as xlate, DEFAULT_LOCALE } from "../api/i18n";
import type { ICompositeSelection } from "../api/common";

import { strIsNullOrEmpty } from "../utils/string";
import DOMPurify from "dompurify";
import { TypedSelect, useElementContext } from "./elements/element-context";

/**
 * Context information provided to the cell value customization functions of the Selection Panel
 *
 * @since 0.15
 */
export interface ISelectionPanelCellContext {
    /**
     * The name of the property being rendered in the cell
     */
    propertyName: string;
    /**
     * The name of the active selection layer containing this property
     */
    layerName: string | undefined;
}

export interface ISelectedFeatureProps {
    selectedFeature: SelectedFeature;
    selectedLayer?: LayerMetadata;
    /**
     * The name of the active selection layer
     *
     * @since 0.15
     */
    layerName?: string;
    locale: string;
    allowHtmlValues: boolean;
    /**
     * An optional function for sanitizing/transforming a HTML property value before it is rendered.
     * The context parameter provides additional information about the property being rendered,
     * allowing for fine-grained control over what kind of content to clean/reformat.
     *
     * @since 0.15 Added context parameter
     */
    cleanHTML?: (html: string, context: ISelectionPanelCellContext) => string;
    /**
     * An optional function for formatting/transforming a property value before it is displayed.
     * This function is called for all property values regardless of the allowHtmlValues setting,
     * making it the preferred hook for transforming plain text values such as decimal numbers.
     *
     * @since 0.15
     */
    formatPropertyValue?: (value: string, context: ISelectionPanelCellContext) => string;
}

const DefaultSelectedFeature = (props: ISelectedFeatureProps) => {
    const { selectedFeature, selectedLayer, layerName, locale, allowHtmlValues, cleanHTML, formatPropertyValue } = props;
    const { HtmlTable } = useElementContext();
    const featureProps = [] as FeatureProperty[];
    if (selectedLayer?.Property) {
        for (const lp of selectedLayer.Property) {
            const matches = selectedFeature.Property.filter(fp => fp.Name === lp.DisplayName);
            if (matches.length === 1) {
                featureProps.push(matches[0]);
            }
        }
    } else {
        for (const fp of selectedFeature.Property) {
            featureProps.push(fp);
        }
    }
    return <HtmlTable condensed bordered className="selection-panel-property-grid">
        <thead>
            <tr>
                <th>{xlate("SELECTION_PROPERTY", locale)}</th>
                <th>{xlate("SELECTION_VALUE", locale)}</th>
            </tr>
        </thead>
        <tbody>
            {featureProps.map(prop => {
                return <tr key={prop.Name}>
                    <td className="property-name-cell" data-property-name={prop.Name}>{prop.Name}</td>
                    {(() => {
                        const context: ISelectionPanelCellContext = { propertyName: prop.Name, layerName };
                        let value = prop.Value;
                        if (formatPropertyValue && !strIsNullOrEmpty(value)) {
                            value = formatPropertyValue(value, context);
                        }
                        if (allowHtmlValues && !strIsNullOrEmpty(value)) {
                            if (cleanHTML) {
                                value = cleanHTML(value, context);
                            } else {
                                value = DOMPurify.sanitize(value);
                            }
                            return <td className="property-value-cell" data-property-value-for={prop.Name} dangerouslySetInnerHTML={{ __html: value }} />
                        } else {
                            return <td className="property-value-cell" data-property-value-for={prop.Name}>{value}</td>;
                        }
                    })()}
                </tr>;
            })}
        </tbody>
    </HtmlTable>;
};

/**
 * SelectionPanel component props
 *
 * @interface ISelectionPanelProps
 */
export interface ISelectionPanelProps {
    locale?: string;
    /**
     * @since 0.14
     */
    selection: ICompositeSelection;
    onResolveLayerLabel?: (layerId: string, layerName: string) => string | undefined;
    onRequestZoomToFeature: (feat: SelectedFeature) => void;
    onShowSelectedFeature: (layerId: string, selectionKey: string) => void;
    maxHeight?: number;
    selectedFeatureRenderer?: (props: ISelectedFeatureProps) => JSX.Element;
    /**
     * Controls whether HTML values are allowed be rendered in property values
     * 
     * @since 0.11
     * @type {boolean}
     */
    allowHtmlValues: boolean;
    /**
     * If allowHtmlValues = true, defines a custom function for sanitizing the given HTML string
     * to guard against cross-site scripting attacks. You are strongly recommended to provide
     * a santitization function if your HTML property values come from an un-trusted source.
     * The context parameter provides additional information about which property is being
     * rendered, enabling fine-grained control over what kind of content to clean/reformat.
     * 
     * @since 0.11
     * @since 0.15 Added context parameter
     */
    cleanHTML?: ISelectedFeatureProps["cleanHTML"];
    /**
     * An optional function for formatting/transforming a property value before it is displayed.
     * This function is called for all property values regardless of the allowHtmlValues setting,
     * making it the preferred hook for transforming plain text values such as decimal numbers.
     *
     * @example
     * // Limit decimal numbers to 3 decimal places
     * formatPropertyValue={(value, context) => {
     *   if (/^-?\d+\.\d+$/.test(value)) {
     *     return parseFloat(value).toFixed(3);
     *   }
     *   return value;
     * }}
     *
     * @since 0.15
     */
    formatPropertyValue?: ISelectedFeatureProps["formatPropertyValue"];
}

interface ISelectionPanel {
    locale: string;
    canGoPrev(): boolean;
    canGoNext(): boolean;
    prevFeature(): void;
    nextFeature(): void;
    canZoomSelectedFeature(): boolean;
    zoomSelectedFeature(): void;
}

function buildToolbarItems(selPanel: ISelectionPanel): IItem[] {
    return [
        {
            svgIconName: "arrow-left",
            tooltip: xlate("SELECTION_PREV_FEATURE", selPanel.locale),
            enabled: () => selPanel.canGoPrev(),
            invoke: () => selPanel.prevFeature()
        },
        {
            svgIconName: "arrow-right",
            tooltip: xlate("SELECTION_NEXT_FEATURE", selPanel.locale),
            enabled: () => selPanel.canGoNext(),
            invoke: () => selPanel.nextFeature()
        },
        { isSeparator: true },
        {
            svgIconName: "path-search",
            tooltip: xlate("SELECTION_ZOOMTO_FEATURE", selPanel.locale),
            enabled: () => selPanel.canZoomSelectedFeature(),
            invoke: () => selPanel.zoomSelectedFeature()
        }
    ];
}

const SELECTION_TOOLBAR_STYLE: React.CSSProperties = { float: "right", height: DEFAULT_TOOLBAR_SIZE };
const SELECTION_PANEL_TOOLBAR_STYLE: React.CSSProperties = { height: DEFAULT_TOOLBAR_SIZE, backgroundColor: TOOLBAR_BACKGROUND_COLOR };
const LAYER_COMBO_STYLE: React.CSSProperties = { float: "left", height: DEFAULT_TOOLBAR_SIZE };
const FloatClear = () => <div style={{ clear: "both" }} />;



/**
 * Displays attributes of selected features with the ability to zoom in on selected features
 * @param props 
 */
export const SelectionPanel = React.memo((props: ISelectionPanelProps) => {
    const { Callout } = useElementContext();
    const {
        maxHeight,
        selection,
        selectedFeatureRenderer,
        allowHtmlValues,
        cleanHTML,
        formatPropertyValue,
        onShowSelectedFeature,
        onRequestZoomToFeature
    } = props;
    const [selectedLayerIndex, setSelectedLayerIndex] = React.useState(-1);
    const [featureIndex, setFeatureIndex] = React.useState(-1);
    React.useEffect(() => {
        if (selection.getLayerCount() > 0) {
            if (selectedLayerIndex < 0) {
                setSelectedLayerIndex(0);
                setFeatureIndex(0);
            } else {
                const sl = selection.getLayerAt(selectedLayerIndex);
                if (!sl) {
                    setSelectedLayerIndex(0);
                    setFeatureIndex(0);
                } else {
                    if (featureIndex < 0 && sl.getFeatureCount() > 0) {
                        setFeatureIndex(0);
                    }
                }
            }
        }
    }, [selection]);
    const getCurrentLayer = () => {
        return selection.getLayerAt(selectedLayerIndex);
    };
    const getFeatureAt = (index: number) => {
        return selection.getFeatureAt(selectedLayerIndex, index);
    };
    const getCurrentFeature = () => {
        return getFeatureAt(featureIndex);
    };
    const canGoPrev = (): boolean => {
        return featureIndex > 0;
    };
    const canGoNext = (): boolean => {
        const layer = getCurrentLayer();
        if (layer != null) {
            return featureIndex + 1 < layer.getFeatureCount();
        }
        return false;
    };
    const canZoomSelectedFeature = (): boolean => {
        const feat = getCurrentFeature();
        return feat?.Bounds != null;
    };
    const prevFeature = () => {
        const newIndex = featureIndex - 1;
        setFeatureIndex(newIndex);
        const layer = getCurrentLayer();
        if (layer) {
            const layerId = layer.getLayerId();
            const sKey = getFeatureAt(newIndex)?.SelectionKey;
            if (sKey && layerId) {
                onShowSelectedFeature?.(layerId, sKey);
            }
        }
    };
    const nextFeature = () => {
        const newIndex = featureIndex + 1;
        setFeatureIndex(newIndex);
        const layer = getCurrentLayer();
        if (layer) {
            const layerId = layer.getLayerId();
            const sKey = getFeatureAt(newIndex)?.SelectionKey;
            if (sKey && layerId) {
                onShowSelectedFeature?.(layerId, sKey);
            }
        }
    };
    const zoomSelectedFeature = () => {
        const feat = getCurrentFeature();
        if (feat) {
            onRequestZoomToFeature(feat);
        }
    };
    const onSelectedLayerChanged = (index: number) => {
        setSelectedLayerIndex(index);
        setFeatureIndex(0);
    };
    const locale = props.locale || DEFAULT_LOCALE;
    let feat: SelectedFeature | undefined;
    let meta: LayerMetadata | undefined;
    let layerName: string | undefined;
    if (selection != null && selectedLayerIndex >= 0 && featureIndex >= 0) {
        const selLayer = selection.getLayerAt(selectedLayerIndex);
        feat = selLayer?.getFeatureAt(featureIndex);
        meta = selLayer?.getLayerMetadata();
        layerName = selLayer?.getName();
    }
    const selectionPanelRootStyle: React.CSSProperties = {};
    let selBodyStyle: React.CSSProperties | undefined;
    if (maxHeight) {
        selectionPanelRootStyle.overflow = "hidden";
        selBodyStyle = {
            overflowY: "auto",
            maxHeight: maxHeight - DEFAULT_TOOLBAR_SIZE
        };
    } else {
        selectionPanelRootStyle.position = "relative";
        selectionPanelRootStyle.width = "100%";
        selectionPanelRootStyle.height = "100%";
        selectionPanelRootStyle.overflow = "hidden";
        selBodyStyle = {
            overflow: "auto",
            position: "absolute",
            top: DEFAULT_TOOLBAR_SIZE,
            bottom: 0,
            right: 0,
            left: 0
        }
    }
    return <div style={selectionPanelRootStyle}>
        {(() => {
            if (selection?.getLayerCount() > 0) {
                const selectionToolbarItems = buildToolbarItems({
                    locale,
                    canGoPrev,
                    canGoNext,
                    prevFeature,
                    nextFeature,
                    canZoomSelectedFeature,
                    zoomSelectedFeature
                });
                return <div className="selection-panel-toolbar" style={SELECTION_PANEL_TOOLBAR_STYLE}>
                    <TypedSelect<number, false> extraClassNames="selection-panel-layer-selector"
                        value={selectedLayerIndex}
                        style={LAYER_COMBO_STYLE}
                        onChange={onSelectedLayerChanged}
                        keyFunc={item => `selected-layer-${item.value}`}
                        items={selection.getLayers().map((layer, index) => {
                            const lid = layer.getLayerId();
                            const lname = layer.getName();
                            const lkey = lid ?? index;
                            const label = lid ? (props?.onResolveLayerLabel?.(lid, lname) ?? lname)
                                : lname;
                            return { value: index, label };
                        })}
                    />
                    <Toolbar childItems={selectionToolbarItems} containerStyle={SELECTION_TOOLBAR_STYLE} />
                    <FloatClear />
                </div>;
            }
        })()}
        <div className="selection-panel-body" style={selBodyStyle}>
            {(() => {
                if (feat) {
                    if (selectedFeatureRenderer) {
                        return selectedFeatureRenderer({ selectedFeature: feat, cleanHTML: cleanHTML, formatPropertyValue: formatPropertyValue, allowHtmlValues: allowHtmlValues, selectedLayer: meta, layerName: layerName, locale: locale });
                    } else {
                        return <DefaultSelectedFeature selectedFeature={feat} cleanHTML={cleanHTML} formatPropertyValue={formatPropertyValue} allowHtmlValues={allowHtmlValues} selectedLayer={meta} layerName={layerName} locale={locale} />;
                    }
                } else if (!(selection?.getLayerCount() > 0)) {
                    return <Callout variant="primary" icon="info-sign">
                        <span className="selection-panel-no-selection">{xlate("NO_SELECTED_FEATURES", locale)}</span>
                    </Callout>;
                }
            })()}
        </div>
    </div>;
});